mapper.update:
update service_order
service_item_id=#{serviceItemId}, worker_id=#{workerId}, address_id=#{addressId}, appointment_time=#{appointmentTime}, order_status=#{status}, pay_status=#{payStatus}, total_amount=#{totalAmount}, remark=#{remark}, cancel_reason=#{cancelReason}, update_time=#{updateTime}, pay_time=#{payTime}, receive_time=#{receiveTime}, start_service_time=#{startServiceTime}, finish_service_time=#{finishServiceTime}, cancel_time=#{cancelTime}
where id=#{id}

mapper.select:
select so.*, u.nickname as userName, u.phone as userPhone, so.order_status as status, case so.order_status when 0 then '待接单' when 1 then '已接单' when 2 then '服务中' when 3 then '已完成' when 4 then '已取消' end as orderStatusName, concat(ad.province,ad.city,ad.district,ad.detail_address) as address, si.name as serviceItemName from service_order so left join user u on so.user_id=u.id left join user_address ad on so.address_id=ad.id left join service_item si on so.service_item_id=si.id
so.worker_id=#{workerId}
and so.order_status=#{status}
order by so.create_time desc
